import React from 'react';

const API_URL = 'https://api.example.com';
const LOCAL_URL = 'http://192.168.';

const apiHeaders = {
  'Accept': 'application/json', 
  'Content-Type': 'application/json'
};

const fetchApi = async (endpoint, options) => {
  try {
    const url = `${API_URL}/${endpoint}`;
    const response = await fetch(url, {
      ...options,
      headers: apiHeaders
    });

    const data = await response.json();
    
    return data;
  } catch (error) {
    console.error(error);
  }
};

const fetchLocal = async (device_number, endpoint, options) => {
  try {
    const url = `${LOCAL_URL}${device_number}/${endpoint}`;
    const response = await fetch(url, {
      ...options,
    });

    const data = await response.json();
    
    return data;
  } catch (error) {
    console.error(error);
  }
};

export const NetworkingModule = {
  fetchApi,
  fetchLocal,
};